  ('social-worker-moex-06220', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '提供一個有用的引導，在取得更深入答案的同時，不會影響後續的回答，這項是質化研究常用的技巧稱為：', '["追問（follow-up）", "面質（query）", "探查（probe）", "查問（inquire）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b0994270630f", "answer_pdf_sha1": "5dead83a85c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06221', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關質性研究的評估標準，對當代實證主義者而言，主要評估質性研究嚴謹度在於信賴度。為了減少研 究誤解的威脅，學者提出幾種普遍適用的策略來提升質性研究的嚴謹度。請問下列何種策略不適宜？', '["焦點團體討論", "成員回饋與校正", "負向案例分析", "三角測量"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b0994270630f", "answer_pdf_sha1": "5dead83a85c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06222', 'social-worker', 'social-worker-moex-104-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某大學調查影響該校學生擔任志工的因素，調查的母群體為下列何者？', '["該大學所有調查時有擔任志工的學生", "該大學所有曾經擔任過志工的學生", "該大學所有有意願擔任志工的學生", "該大學所有學生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "b0994270630f", "answer_pdf_sha1": "5dead83a85c6", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
